import sys, types, threading, time
import contextlib
from assay_engine.persistence import checkpoint as cp

def build_fakes(state):
    class FakeConn:
        def execute(self, sql, params=None):
            if "pg_advisory_lock" in sql:
                state["lock_on"].append(id(self))
    class FakePool:
        check_connection = staticmethod(lambda *a, **k: None)
        def __init__(self, conn_str, **kw):
            self._conn = FakeConn(); state["pools"].append(self)
        def connection(self):
            conn = self._conn
            class _Ctx:
                def __enter__(self_): return conn
                def __exit__(self_, *a): return False
            return _Ctx()
        def close(self): pass
    class FakeSaver:
        def __init__(self, arg): self.arg = arg
        def setup(self):
            time.sleep(0.05)  # WIDEN the race window (per finding's own fix recommendation)
            state["setup_on"].append(id(self.arg))
    return FakePool, FakeSaver

def run():
    state = {"setup_on": [], "lock_on": [], "pools": []}
    FakePool, FakeSaver = build_fakes(state)
    for n in ["langgraph","langgraph.checkpoint","langgraph.checkpoint.postgres",
              "langgraph.checkpoint.memory","psycopg","psycopg.rows","psycopg_pool"]:
        sys.modules[n] = types.ModuleType(n)
    sys.modules["langgraph.checkpoint.postgres"].PostgresSaver = FakeSaver
    sys.modules["langgraph.checkpoint.memory"].MemorySaver = type("M",(),{})
    sys.modules["psycopg.rows"].dict_row = object()
    sys.modules["psycopg_pool"].ConnectionPool = FakePool
    cp._INITIALIZED_CONN_STRS = set(); cp._OPEN_POOLS=[]; cp._atexit_registered=False
    cp._CONN_INIT_LOCKS={}; cp._POOLS_BY_CONN={}
    cp.atexit = types.SimpleNamespace(register=lambda fn: None)
    import os; os.environ["ASSAY_POSTGRES_URL"]="postgresql://localhost:5432/assay"
    barrier = threading.Barrier(8)
    def worker():
        barrier.wait(); cp.get_checkpointer()
    ts=[threading.Thread(target=worker) for _ in range(8)]
    for t in ts: t.start()
    for t in ts: t.join(5)
    print("setup_on count:", len(state["setup_on"]), "pools:", len(state["pools"]))

run()
